import type React from 'react'
import { useEffect, useState } from 'react'
import type { SudokuBoardCell, SudokuGameData } from '../types'

export function useHintCell(
  data: SudokuGameData,
  hintTick: number,
  setActivatedPuzzleCell: React.Dispatch<React.SetStateAction<SudokuBoardCell>>,
): [SudokuBoardCell, React.Dispatch<React.SetStateAction<SudokuBoardCell>>] {
  const [hintCell, setHintCell] = useState<SudokuBoardCell>({ r: -1, c: -1 })

  useEffect(() => {
    if (hintTick <= 0) {
      setHintCell(cell => (cell.r === -1 ? cell : { r: -1, c: -1 }))
      return
    }

    const { SUDOKU_SIZE, puzzle, attempt, solution } = data
    setActivatedPuzzleCell(cell => {
      let { r, c } = cell
      if (r === -1 || attempt[r][c] !== -1) {
        const candidateHintCell = findCandidateHintCell()
        if (candidateHintCell === null) return cell

        r = candidateHintCell.r
        c = candidateHintCell.c
      }

      setHintCell({ r, c, v: solution[r][c] })
      return cell.r === r && cell.c === c ? cell : { r, c }
    })

    function findCandidateHintCell(): SudokuBoardCell | null {
      let r = 0
      let c = 0

      // Empty cell first.
      for (; r < SUDOKU_SIZE; ++r) {
        for (; c < SUDOKU_SIZE; ++c) {
          if (attempt[r][c] === -1) {
            return { r, c }
          }
        }
      }

      // Find a incorrect grid.
      for (; r < SUDOKU_SIZE; ++r) {
        for (; c < SUDOKU_SIZE; ++c) {
          if (puzzle[r][c] === -1 && attempt[r][c] !== solution[r][c]) {
            return { r, c }
          }
        }
      }

      return null
    }
  }, [hintTick, data, setActivatedPuzzleCell])
  return [hintCell, setHintCell]
}

export default useHintCell
