/**
 * Game running state.
 */
export enum GameRunningState {
  /**
   * The game is in the ready state and has not started yet.
   */
  PENDING = 0,
  /**
   * The game is running.
   */
  RUNNING = 1,
  /**
   * The game is paused.
   */
  PAUSED = 2,
  /**
   * The game is finished.
   */
  FINISHED = 3,
}
