/* eslint-disable no-param-reassign */
import type { SudokuBoard } from '@algorithm.ts/sudoku'
import type React from 'react'
import { useCallback, useEffect, useState } from 'react'
import type { SudokuBoardCell, SudokuGameData } from '../types'
import { patchDuplicatedMap } from '../util'

export type CellInputHandler = (v: number, r?: number, c?: number) => void

/**
 * Returns whether the game is over
 *
 * @param data
 * @param setActivatedPuzzleCell
 * @param setHintCell
 * @param inputRef
 * @returns
 */
export function useCellInputRef(
  data: SudokuGameData,
  setActivatedPuzzleCell: React.Dispatch<React.SetStateAction<SudokuBoardCell>>,
  setHintCell: React.Dispatch<React.SetStateAction<SudokuBoardCell>>,
  inputRef?: React.RefObject<CellInputHandler>,
): boolean {
  const [gameFinished, setGameFinished] = useState<boolean>(false)
  const handleCellInput = useCallback<CellInputHandler>(
    (v, _r, _c): void => {
      const { SUDOKU_SIZE_SQRT, SUDOKU_SIZE, puzzle } = data

      // Update current activated cell.
      setActivatedPuzzleCell(cell => {
        const r = _r ?? cell.r
        const c = _c ?? cell.c
        solve(r, c)
        return cell.r === r && cell.c === c ? cell : { r, c }
      })

      function solve(r: number, c: number): void {
        if (
          !Number.isInteger(v) ||
          v < -1 ||
          v >= SUDOKU_SIZE ||
          !Number.isInteger(r) ||
          !Number.isInteger(c) ||
          r < 0 ||
          r >= SUDOKU_SIZE ||
          c < 0 ||
          c >= SUDOKU_SIZE ||
          puzzle[r][c] !== -1
        )
          return

        // Cannot change value on this grid.
        if (puzzle[r][c] !== -1) return

        // Cancel hint.
        setHintCell({ r: -1, c: -1 })
        const { attempt, solution } = data
        if (attempt[r][c] === v) return
        attempt[r][c] = v

        setGameFinished(
          attempt[r][c] === solution[r][c]
            ? checkCompleted(SUDOKU_SIZE, attempt, solution)
            : false,
        )

        const { duplicatedMap, segmentNoMap } = data
        patchDuplicatedMap(
          SUDOKU_SIZE_SQRT,
          r,
          c,
          attempt,
          duplicatedMap,
          segmentNoMap,
        )
      }
    },
    [data, setActivatedPuzzleCell, setHintCell],
  )

  useEffect(() => {
    if (inputRef == null) return
    ;(inputRef as any).current = handleCellInput
  }, [handleCellInput, inputRef])

  return gameFinished
}

export default useCellInputRef

/**
 * Check if the puzzle solved.
 * @param SUDOKU_SIZE
 * @param attempt
 * @param solution
 * @returns
 */
function checkCompleted(
  SUDOKU_SIZE: number,
  attempt: Readonly<SudokuBoard>,
  solution: Readonly<SudokuBoard>,
): boolean {
  for (let r = 0; r < SUDOKU_SIZE; ++r) {
    for (let c = 0; c < SUDOKU_SIZE; ++c) {
      if (attempt[r][c] !== solution[r][c]) return false
    }
  }
  return true
}
